   private async withRetry<T>(op: () => Promise<T>): Promise<T> {
     let lastError: unknown;
-    for (let attempt = 0; attempt < 3; attempt++) {
+    const delays = [50, 150, 450];
+    for (let attempt = 0; attempt < delays.length; attempt++) {
       try {
